// server/middleware/correlation.ts
import { randomUUID } from 'crypto';
import { RequestHandler } from 'express';
export const correlationId: RequestHandler = (req, res, next) => {
  const id = req.header('x-correlation-id') ?? randomUUID();
  (req as any).correlationId = id;
  res.setHeader('x-correlation-id', id);
  next();
};

// server/middleware/errorHandler.ts
import { ErrorRequestHandler } from 'express';
import { AppError } from '../errors';
export const errorHandler: ErrorRequestHandler = (err, req, res, _next) => {
  const correlationId = (req as any).correlationId;
  if (err instanceof AppError) {
    req.log.warn({ err, correlationId }, 'app error');
    return res.status(err.status).json({ code: err.code, message: err.message, correlationId, fields: err.fields });
  }
  req.log.error({ err, correlationId }, 'unhandled error');
  res.status(500).json({ code: 'INTERNAL', message: 'Internal error', correlationId });
};

