// client/lib/fetcher.ts
import { ApiErrorSchema, type ApiError } from '@shared/schemas/fetch';

export class FetchError extends Error {
  constructor(public status: number, public body: ApiError | null, public correlationId: string | null) {
    super(body?.message ?? `HTTP ${status}`);
  }
  get retryable() { return this.status >= 500 || this.status === 429; }
}

const inflight = new Map<string, Promise<unknown>>();

export async function fetcher<T>(url: string, init: RequestInit & { signal?: AbortSignal } = {}, parse: (raw: unknown) => T): Promise<T> {
  const key = `${init.method ?? 'GET'} ${url} ${init.body ?? ''}`;
  const cached = inflight.get(key);
  if (cached) return cached as Promise<T>;
  const p = (async () => {
    const res = await fetch(url, init);
    const corrId = res.headers.get('x-correlation-id');
    if (!res.ok) {
      const raw = await res.json().catch(() => null);
      const parsed = raw ? ApiErrorSchema.safeParse(raw) : null;
      throw new FetchError(res.status, parsed?.success ? parsed.data : null, corrId);
    }
    return parse(await res.json());
  })().finally(() => inflight.delete(key));
  inflight.set(key, p);
  return p as Promise<T>;
}

// client/hooks/useFetch.ts
import { useEffect, useReducer, useRef } from 'react';
import { fetcher, FetchError } from '../lib/fetcher';

type State<T> = { status: 'idle' } | { status: 'loading' } | { status: 'success'; data: T } | { status: 'error'; error: FetchError };

const backoff = (attempt: number) => Math.min(8000, 200 * 2 ** attempt) * (0.5 + Math.random() * 0.5);

export function useFetch<T>(url: string | null, parse: (raw: unknown) => T, opts: { maxRetries?: number } = {}) {
  const [state, dispatch] = useReducer((_: State<T>, next: State<T>) => next, { status: 'idle' });
  const abortRef = useRef<AbortController | null>(null);

  useEffect(() => {
    if (!url) return;
    const controller = new AbortController();
    abortRef.current = controller;
    let cancelled = false;
    (async () => {
      dispatch({ status: 'loading' });
      let attempt = 0;
      while (true) {
        try {
          const data = await fetcher(url, { signal: controller.signal }, parse);
          if (!cancelled) dispatch({ status: 'success', data });
          return;
        } catch (e) {
          if (controller.signal.aborted) return;
          const err = e instanceof FetchError ? e : new FetchError(0, null, null);
          if (!err.retryable || attempt >= (opts.maxRetries ?? 3)) {
            if (!cancelled) dispatch({ status: 'error', error: err });
            return;
          }
          await new Promise(r => setTimeout(r, backoff(attempt++)));
        }
      }
    })();
    return () => { cancelled = true; controller.abort(); };
  }, [url]);

  return state;
}

