// client/hooks/useLocalStorage.ts
import { useCallback, useEffect, useState, useSyncExternalStore } from 'react';
import { z, ZodSchema } from 'zod';

function read<T>(key: string, schema: ZodSchema<T>, fallback: T): T {
  try {
    const raw = localStorage.getItem(key);
    if (raw === null) return fallback;
    const parsed = schema.safeParse(JSON.parse(raw));
    if (!parsed.success) { console.warn('localStorage parse failed', { key, raw: raw.slice(0, 80) }); return fallback; }
    return parsed.data;
  } catch (e) { console.warn('localStorage read failed', { key, e }); return fallback; }
}

const listeners = new Map<string, Set<() => void>>();
function subscribe(key: string, cb: () => void) {
  if (!listeners.has(key)) listeners.set(key, new Set());
  listeners.get(key)!.add(cb);
  const onStorage = (e: StorageEvent) => { if (e.key === key) cb(); };
  window.addEventListener('storage', onStorage);
  return () => { listeners.get(key)!.delete(cb); window.removeEventListener('storage', onStorage); };
}

export function useLocalStorage<T>(key: string, schema: ZodSchema<T>, defaultValue: T): [T, (next: T | ((p: T) => T)) => void] {
  const getSnapshot = useCallback(() => {
    if (typeof window === 'undefined') return JSON.stringify(defaultValue);
    return localStorage.getItem(key) ?? JSON.stringify(defaultValue);
  }, [key, defaultValue]);
  const subscribeKey = useCallback((cb: () => void) => subscribe(key, cb), [key]);
  const raw = useSyncExternalStore(subscribeKey, getSnapshot, () => JSON.stringify(defaultValue));
  const value = read(key, schema, defaultValue);
  const setValue = useCallback((next: T | ((p: T) => T)) => {
    const resolved = typeof next === 'function' ? (next as (p: T) => T)(value) : next;
    try {
      localStorage.setItem(key, JSON.stringify(resolved));
      listeners.get(key)?.forEach(cb => cb());
    } catch (e) { console.error('localStorage write failed', { key, e }); }
  }, [key, value]);
  return [value, setValue];
}

