// server/errors/index.ts
import type { ErrorCode } from '@shared/schemas/errors';

export abstract class AppError extends Error {
  abstract readonly code: ErrorCode;
  abstract readonly status: number;
  readonly fields?: Record<string, string>;
  readonly meta?: Record<string, unknown>;
  constructor(message: string, opts: { fields?: Record<string, string>; meta?: Record<string, unknown>; cause?: unknown } = {}) {
    super(message, { cause: opts.cause });
    this.fields = opts.fields;
    this.meta = opts.meta;
  }
}
export class ValidationError extends AppError { readonly code = 'VALIDATION_FAILED' as const; readonly status = 400; }
export class NotFoundError extends AppError { readonly code = 'NOT_FOUND' as const; readonly status = 404; }
export class ConflictError extends AppError { readonly code = 'CONFLICT' as const; readonly status = 409; }
export class UnauthorizedError extends AppError { readonly code = 'UNAUTHORIZED' as const; readonly status = 401; }
export class ForbiddenError extends AppError { readonly code = 'FORBIDDEN' as const; readonly status = 403; }
export class QuotaError extends AppError { readonly code = 'QUOTA_EXCEEDED' as const; readonly status = 402; }
export class BillingError extends AppError { readonly code = 'BILLING_PAST_DUE' as const; readonly status = 402; }
export class RateLimitError extends AppError { readonly code = 'RATE_LIMITED' as const; readonly status = 429; }

// server/middleware/errorHandler.ts
import { ErrorRequestHandler } from 'express';
import { ZodError } from 'zod';
import { AppError, ValidationError } from '../errors';

export const errorHandler: ErrorRequestHandler = (err, req, res, _next) => {
  const correlationId = (req as any).correlationId;
  let normalized: AppError;
  if (err instanceof AppError) normalized = err;
  else if (err instanceof ZodError) normalized = new ValidationError('Validation failed', { fields: Object.fromEntries(err.issues.map(i => [i.path.join('.'), i.message])) });
  else normalized = Object.assign(new (class extends AppError { code = 'INTERNAL' as const; status = 500; })('Internal error'), { cause: err });
  if (normalized.status >= 500) req.log.error({ err: normalized, cause: normalized.cause, correlationId }, normalized.code);
  else req.log.warn({ code: normalized.code, fields: normalized.fields, correlationId, path: req.path }, normalized.code);
  res.status(normalized.status).json({
    code: normalized.code,
    message: normalized.status >= 500 ? 'Internal error' : normalized.message,
    correlationId,
    fields: normalized.fields,
    meta: normalized.meta
  });
};

// server/services/projectService.ts (example usage)
import { ConflictError, QuotaError } from '../errors';
export async function createProject(tenantId: string, input: { name: string }) {
  const tenant = await dal.getTenant(tenantId);
  if (tenant.projectCount >= tenant.plan.projectLimit) throw new QuotaError('Plan project limit reached', { meta: { upgradeUrl: '/billing/upgrade', current: tenant.projectCount, limit: tenant.plan.projectLimit } });
  if (await dal.projectExistsByName(tenantId, input.name)) throw new ConflictError('Project name already in use', { fields: { name: 'Name already in use' } });
  return dal.createProject(tenantId, input);
}

