// client/components/CreateProjectForm.tsx
import { useState } from 'react';
import { FetchError } from '../lib/fetcher';
import type { ApiError } from '@shared/schemas/errors';

export function CreateProjectForm() {
  const [name, setName] = useState('');
  const [fieldErrors, setFieldErrors] = useState<Record<string, string>>({});
  const [banner, setBanner] = useState<{ kind: 'quota' | 'billing' | 'unknown'; meta?: any } | null>(null);
  const [submitting, setSubmitting] = useState(false);

  async function onSubmit(e: React.FormEvent) {
    e.preventDefault();
    setSubmitting(true); setFieldErrors({}); setBanner(null);
    try {
      await api.createProject({ name });
      // success path
    } catch (err) {
      if (err instanceof FetchError && err.body) {
        switch (err.body.code) {
          case 'VALIDATION_FAILED':
          case 'CONFLICT':
            setFieldErrors(err.body.fields ?? {}); break;
          case 'QUOTA_EXCEEDED':
            setBanner({ kind: 'quota', meta: err.body.meta }); break;
          case 'BILLING_PAST_DUE':
            setBanner({ kind: 'billing' }); break;
          default:
            setBanner({ kind: 'unknown' });
        }
      } else setBanner({ kind: 'unknown' });
    } finally { setSubmitting(false); }
  }

  return (
    <form onSubmit={onSubmit} className="space-y-4">
      {banner?.kind === 'quota' && <QuotaBanner meta={banner.meta} />}
      {banner?.kind === 'billing' && <BillingBanner />}
      {banner?.kind === 'unknown' && <ErrorBanner />}
      <Field label="Name" error={fieldErrors.name}>
        <input value={name} onChange={e => setName(e.target.value)} aria-invalid={!!fieldErrors.name} />
      </Field>
      <button disabled={submitting} type="submit">{submitting ? 'Creating…' : 'Create'}</button>
    </form>
  );
}

