// client/components/ErrorBoundary.tsx
import { Component, ReactNode } from 'react';
import * as Sentry from '@sentry/react';

type Props = { resetKey?: string; fallback: (props: { error: Error; reset: () => void }) => ReactNode; children: ReactNode };
type State = { error: Error | null };

export class ErrorBoundary extends Component<Props, State> {
  state: State = { error: null };
  static getDerivedStateFromError(error: Error): State { return { error }; }
  componentDidCatch(error: Error, info: React.ErrorInfo) {
    Sentry.withScope(scope => {
      scope.setContext('react', { componentStack: info.componentStack });
      scope.setTag('boundary_key', this.props.resetKey ?? 'root');
      Sentry.captureException(error);
    });
  }
  componentDidUpdate(prev: Props) {
    if (this.state.error && prev.resetKey !== this.props.resetKey) this.setState({ error: null });
  }
  reset = () => this.setState({ error: null });
  render() {
    if (this.state.error) return this.props.fallback({ error: this.state.error, reset: this.reset });
    return this.props.children;
  }
}

// client/hooks/useAsyncError.ts — throw async errors INTO the nearest boundary
import { useCallback, useState } from 'react';
export function useAsyncError() {
  const [, setError] = useState();
  return useCallback((e: unknown) => { setError(() => { throw e instanceof Error ? e : new Error(String(e)); }); }, []);
}

// client/components/RouteBoundary.tsx
import { useLocation } from 'react-router-dom';
import { ErrorBoundary } from './ErrorBoundary';
export function RouteBoundary({ children }: { children: React.ReactNode }) {
  const { pathname } = useLocation();
  return (
    <ErrorBoundary resetKey={pathname} fallback={({ error, reset }) => (
      <div role="alert" className="max-w-md mx-auto mt-16 p-6 border rounded">
        <h2 className="text-lg font-semibold">Something went wrong in this section</h2>
        <p className="text-sm text-gray-600 mt-2">We've been notified. You can try again or go back to the dashboard.</p>
        <div className="mt-4 flex gap-2">
          <button onClick={reset} className="px-3 py-2 bg-blue-600 text-white rounded">Try again</button>
          <a href="/" className="px-3 py-2 border rounded">Go to dashboard</a>
        </div>
        {import.meta.env.DEV && <pre className="text-xs mt-4 text-red-600 overflow-auto">{error.stack}</pre>}
      </div>
    )}>
      {children}
    </ErrorBoundary>
  );
}

