// server/models/User.ts — Mongoose with Zod validation in pre-save
import mongoose from 'mongoose';
import { UserProfileSchema } from '@shared/schemas/user';
const userSchema = new mongoose.Schema({
  email: { type: String, required: true, unique: true, index: true },
  fullName: { type: String, required: true },
  phone: String,
  timezone: { type: String, required: true },
  locale: { type: String, required: true },
  marketingOptIn: { type: Boolean, default: false }
}, { timestamps: true });
userSchema.pre('save', function(next) {
  const parsed = UserProfileSchema.omit({ id: true }).safeParse({ ...this.toObject(), id: this._id.toString() });
  if (!parsed.success) return next(parsed.error);
  next();
});
export const UserModel = mongoose.model('User', userSchema);

// server/middleware/validateBody.ts
import { ZodSchema } from 'zod';
import { RequestHandler } from 'express';
import { ValidationError } from '../errors';
export const validateBody = <T>(schema: ZodSchema<T>): RequestHandler => (req, _res, next) => {
  const parsed = schema.safeParse(req.body);
  if (!parsed.success) return next(new ValidationError('Invalid input', { fields: Object.fromEntries(parsed.error.issues.map(i => [i.path.join('.'), i.message])) }));
  req.body = parsed.data;
  next();
};

