// server/context/tenantContext.ts
import { AsyncLocalStorage } from 'node:async_hooks';
import type { TenantId } from '@shared/schemas/tenant';
const store = new AsyncLocalStorage<{ tenantId: TenantId; userId: string }>();
export const tenantContext = {
  run<T>(ctx: { tenantId: TenantId; userId: string }, fn: () => T) { return store.run(ctx, fn); },
  current() { return store.getStore(); },
  requireTenant(): TenantId {
    const ctx = store.getStore();
    if (!ctx) throw new Error('TENANT_CONTEXT_MISSING: no tenant context in current async scope');
    return ctx.tenantId;
  }
};

// server/middleware/tenantMiddleware.ts
import { RequestHandler } from 'express';
import { tenantContext } from '../context/tenantContext';
import { UnauthorizedError } from '../errors';
export const requireTenant: RequestHandler = (req, _res, next) => {
  const user = (req as any).user;
  if (!user?.tenantId) return next(new UnauthorizedError('No tenant'));
  tenantContext.run({ tenantId: user.tenantId, userId: user.id }, () => next());
};

// server/dal/projectsDal.ts — every method threads tenantId automatically
import { ProjectModel } from '../models/Project';
import { tenantContext } from '../context/tenantContext';
import { NotFoundError } from '../errors';
export const projectsDal = {
  async list(filter: Partial<{ name: string }> = {}) {
    const tenantId = tenantContext.requireTenant();
    return ProjectModel.find({ tenantId, ...filter }).sort({ createdAt: -1 }).lean();
  },
  async byId(id: string) {
    const tenantId = tenantContext.requireTenant();
    const doc = await ProjectModel.findOne({ _id: id, tenantId }).lean();
    if (!doc) throw new NotFoundError('Project not found');
    return doc;
  },
  async create(input: { name: string }) {
    const tenantId = tenantContext.requireTenant();
    return ProjectModel.create({ ...input, tenantId });
  },
  async update(id: string, patch: Partial<{ name: string }>) {
    const tenantId = tenantContext.requireTenant();
    const updated = await ProjectModel.findOneAndUpdate({ _id: id, tenantId }, patch, { new: true }).lean();
    if (!updated) throw new NotFoundError('Project not found');
    return updated;
  },
  async remove(id: string) {
    const tenantId = tenantContext.requireTenant();
    const r = await ProjectModel.deleteOne({ _id: id, tenantId });
    if (r.deletedCount === 0) throw new NotFoundError('Project not found');
  }
};

// server/jobs/runWithTenant.ts — background jobs MUST seed context explicitly
import { tenantContext } from '../context/tenantContext';
import type { TenantId } from '@shared/schemas/tenant';
export function runWithTenant<T>(tenantId: TenantId, userId: string, fn: () => Promise<T>) {
  return tenantContext.run({ tenantId, userId }, fn);
}

