// server/routes/stripeWebhook.ts
import express, { Router } from 'express';
import Stripe from 'stripe';
import { WebhookInboxModel } from '../models/WebhookInbox';
import { enqueue } from '../jobs/queue';

const stripe = new Stripe(process.env.STRIPE_SECRET_KEY!);
const WEBHOOK_SECRET = process.env.STRIPE_WEBHOOK_SECRET!;
export const stripeWebhookRouter = Router();

stripeWebhookRouter.post('/stripe/webhook', express.raw({ type: 'application/json' }), async (req, res) => {
  const sig = req.header('stripe-signature');
  if (!sig) return res.status(400).send('Missing signature');
  let event: Stripe.Event;
  try {
    event = stripe.webhooks.constructEvent(req.body, sig, WEBHOOK_SECRET);
  } catch (err) {
    req.log.warn({ err }, 'stripe_signature_invalid');
    return res.status(400).send('Invalid signature');
  }
  try {
    await WebhookInboxModel.create({ eventId: event.id, type: event.type, payload: event, status: 'pending', receivedAt: new Date() });
    await enqueue('stripe.process', { eventId: event.id });
  } catch (err: any) {
    if (err.code === 11000) {
      req.log.info({ eventId: event.id }, 'stripe_event_duplicate_ignored');
      return res.status(200).end();
    }
    req.log.error({ err, eventId: event.id }, 'stripe_inbox_write_failed');
    return res.status(500).end();
  }
  res.status(200).end();
});

// server/jobs/processStripeEvent.ts
import Stripe from 'stripe';
import { WebhookInboxModel } from '../models/WebhookInbox';
import { SubscriptionModel } from '../models/Subscription';
import { logger } from '../logger';
const stripe = new Stripe(process.env.STRIPE_SECRET_KEY!);

export async function processStripeEvent({ eventId }: { eventId: string }) {
  const claimed = await WebhookInboxModel.findOneAndUpdate(
    { eventId, status: 'pending' },
    { $set: { status: 'processing', processingStartedAt: new Date() } },
    { new: true }
  );
  if (!claimed) { logger.info({ eventId }, 'stripe_event_already_claimed'); return; }
  const t0 = Date.now();
  try {
    const event = claimed.payload as Stripe.Event;
    switch (event.type) {
      case 'customer.subscription.created':
      case 'customer.subscription.updated': {
        const subPayload = event.data.object as Stripe.Subscription;
        const fresh = await stripe.subscriptions.retrieve(subPayload.id);
        await SubscriptionModel.findOneAndUpdate(
          { stripeSubscriptionId: fresh.id },
          {
            stripeCustomerId: fresh.customer as string,
            status: fresh.status,
            plan: planFromPriceId(fresh.items.data[0].price.id),
            currentPeriodEnd: new Date(fresh.current_period_end * 1000),
            cancelAtPeriodEnd: fresh.cancel_at_period_end
          },
          { upsert: true }
        );
        break;
      }
      case 'invoice.payment_failed': await markPastDue((event.data.object as Stripe.Invoice).subscription as string); break;
      case 'customer.subscription.deleted': await markCanceled((event.data.object as Stripe.Subscription).id); break;
      default: logger.info({ type: event.type, eventId }, 'stripe_event_unhandled');
    }
    await WebhookInboxModel.updateOne({ eventId }, { status: 'processed', processedAt: new Date(), durationMs: Date.now() - t0 });
  } catch (err) {
    logger.error({ err, eventId, durationMs: Date.now() - t0 }, 'stripe_event_processing_failed');
    await WebhookInboxModel.updateOne({ eventId }, { status: 'failed', $inc: { attempts: 1 }, lastError: String(err) });
    throw err;
  }
}

