// client/components/BillingStatus.tsx — reflects subscription state with eventual-consistency awareness
import { useEffect, useState } from 'react';
import { subscriptionApi } from '../api/subscription';
import type { Subscription } from '@shared/schemas/billing';
export function BillingStatus() {
  const [sub, setSub] = useState<Subscription | null>(null);
  const [staleHint, setStaleHint] = useState(false);
  useEffect(() => {
    let cancelled = false;
    subscriptionApi.get().then(s => !cancelled && setSub(s));
    return () => { cancelled = true; };
  }, []);
  // After user returns from Stripe checkout, webhook may not have processed yet
  useEffect(() => {
    if (window.location.search.includes('checkout_complete')) {
      setStaleHint(true);
      const interval = setInterval(async () => {
        const fresh = await subscriptionApi.get();
        setSub(fresh);
        if (fresh.status === 'active') { clearInterval(interval); setStaleHint(false); }
      }, 2000);
      const timeout = setTimeout(() => clearInterval(interval), 30000);
      return () => { clearInterval(interval); clearTimeout(timeout); };
    }
  }, []);
  if (!sub) return <Skeleton />;
  return (
    <div>
      <div>Plan: {sub.plan}</div>
      <div>Status: <StatusPill status={sub.status} /></div>
      {staleHint && <p className="text-sm text-gray-600">Updating subscription — this can take a moment.</p>}
      {sub.status === 'past_due' && <PastDueBanner />}
    </div>
  );
}

