// server/auth/authorize.ts
import { ROLE_GRANTS, type Action, type Role } from '@shared/schemas/permissions';
import { ForbiddenError } from '../errors';
import { tenantContext } from '../context/tenantContext';
import { logger } from '../logger';

export function can(role: Role, action: Action, ctx?: { resource?: { createdBy?: string }; userId?: string }): boolean {
  const grants = ROLE_GRANTS[role];
  if (action.endsWith(':update_own') || action.endsWith(':delete_own')) {
    if (!ctx?.resource || ctx.resource.createdBy !== ctx.userId) return false;
  }
  return grants.includes(action);
}

export function authorize(role: Role, action: Action, opts?: { resource?: { createdBy?: string } }) {
  const ctx = tenantContext.current();
  const allowed = can(role, action, { resource: opts?.resource, userId: ctx?.userId });
  if (!allowed) {
    logger.warn({ userId: ctx?.userId, role, action, resourceCreatedBy: opts?.resource?.createdBy }, 'auth_denied');
    throw new ForbiddenError(`Not permitted: ${action}`);
  }
  logger.info({ userId: ctx?.userId, action }, 'auth_allowed');
}

// server/services/projectService.ts
import { authorize } from '../auth/authorize';
import { projectsDal } from '../dal/projectsDal';
import { tenantContext } from '../context/tenantContext';
export const projectService = {
  async update(id: string, patch: { name?: string }) {
    const ctx = tenantContext.current()!;
    const existing = await projectsDal.byId(id);
    const role = await getRole(ctx.userId, ctx.tenantId);
    try { authorize(role, 'project:update_any'); }
    catch { authorize(role, 'project:update_own', { resource: existing }); }
    return projectsDal.update(id, patch);
  },
  async remove(id: string) {
    const ctx = tenantContext.current()!;
    const existing = await projectsDal.byId(id);
    const role = await getRole(ctx.userId, ctx.tenantId);
    try { authorize(role, 'project:delete_any'); }
    catch { authorize(role, 'project:delete_own', { resource: existing }); }
    await projectsDal.remove(id);
  }
};

