// client/context/PermissionsContext.tsx
import { createContext, useContext, useMemo } from 'react';
import { ROLE_GRANTS, type Action, type Role } from '@shared/schemas/permissions';
type PermissionsValue = { role: Role; can: (action: Action, resource?: { createdBy?: string }) => boolean };
const Ctx = createContext<PermissionsValue | null>(null);
export function PermissionsProvider({ role, userId, children }: { role: Role; userId: string; children: React.ReactNode }) {
  const value = useMemo<PermissionsValue>(() => ({
    role,
    can: (action, resource) => {
      const grants = ROLE_GRANTS[role];
      if (action.endsWith(':update_own') || action.endsWith(':delete_own')) {
        return resource?.createdBy === userId && grants.includes(action);
      }
      return grants.includes(action);
    }
  }), [role, userId]);
  return <Ctx.Provider value={value}>{children}</Ctx.Provider>;
}
export const usePermissions = () => { const c = useContext(Ctx); if (!c) throw new Error('PermissionsProvider missing'); return c; };

// client/components/Can.tsx
import { usePermissions } from '../context/PermissionsContext';
import type { Action } from '@shared/schemas/permissions';
export function Can({ do: action, on, children, fallback = null }: { do: Action | Action[]; on?: { createdBy?: string }; children: React.ReactNode; fallback?: React.ReactNode }) {
  const { can } = usePermissions();
  const actions = Array.isArray(action) ? action : [action];
  const allowed = actions.some(a => can(a, on));
  return <>{allowed ? children : fallback}</>;
}

