// server/services/revenueService.ts — fills sparse dates with nulls
export const revenueService = {
  async trend({ days }: { days: number }) {
    const raw = await revenueDal.dailyArr({ days });
    const byDate = new Map(raw.map(r => [r.date.toISOString().slice(0, 10), r.arr]));
    const points: { date: Date; arr: number | null }[] = [];
    const start = new Date(); start.setDate(start.getDate() - days);
    for (let i = 0; i <= days; i++) {
      const d = new Date(start); d.setDate(start.getDate() + i);
      const key = d.toISOString().slice(0, 10);
      points.push({ date: d, arr: byDate.get(key) ?? null });
    }
    return { points: points.filter(p => p.arr !== null), currency: 'USD' };
  }
};

