import { LineChart, Line, XAxis, YAxis, Tooltip, ResponsiveContainer, ReferenceDot } from 'recharts';
import { useEffect, useState } from 'react';
import { RevenueSeriesSchema, type RevenueSeries } from '@shared/schemas/revenue';
import { fetcher } from '../lib/fetcher';

type State = { status: 'loading' } | { status: 'empty' } | { status: 'single'; point: RevenueSeries['points'][0]; currency: string } | { status: 'ready'; data: RevenueSeries } | { status: 'error'; error: Error };

export function RevenueTrendChart() {
  const [state, setState] = useState<State>({ status: 'loading' });
  useEffect(() => {
    let cancelled = false;
    (async () => {
      try {
        const data = await fetcher<RevenueSeries>('/api/revenue/trend', {}, raw => RevenueSeriesSchema.parse(raw));
        if (cancelled) return;
        if (data.points.length === 0) setState({ status: 'empty' });
        else if (data.points.length === 1) setState({ status: 'single', point: data.points[0], currency: data.currency });
        else setState({ status: 'ready', data });
      } catch (e) { if (!cancelled) setState({ status: 'error', error: e as Error }); }
    })();
    return () => { cancelled = true; };
  }, []);

  return (
    <div className="h-80 w-full" role="region" aria-label="Annual recurring revenue trend">
      {state.status === 'loading' && <ChartSkeleton />}
      {state.status === 'empty' && <EmptyChartState />}
      {state.status === 'single' && <SinglePointChart point={state.point} currency={state.currency} />}
      {state.status === 'error' && <ChartErrorState error={state.error} onRetry={() => setState({ status: 'loading' })} />}
      {state.status === 'ready' && <ReadyChart data={state.data} />}
    </div>
  );
}

function ReadyChart({ data }: { data: RevenueSeries }) {
  const first = data.points[0].arr;
  const last = data.points[data.points.length - 1].arr;
  const summary = `ARR from ${formatMoney(first, data.currency)} to ${formatMoney(last, data.currency)} over ${data.points.length} days`;
  return (
    <ResponsiveContainer width="100%" height="100%">
      <LineChart data={data.points} aria-label={summary}>
        <XAxis dataKey="date" tickFormatter={d => new Date(d).toLocaleDateString(undefined, { month: 'short', day: 'numeric' })} stroke="var(--chart-axis)" />
        <YAxis tickFormatter={v => formatMoney(v, data.currency)} stroke="var(--chart-axis)" />
        <Tooltip content={<AccessibleTooltip currency={data.currency} />} />
        <Line type="monotone" dataKey="arr" stroke="var(--chart-line)" strokeWidth={2} dot={false} connectNulls={false} isAnimationActive={data.points.length < 200} />
      </LineChart>
    </ResponsiveContainer>
  );
}

function AccessibleTooltip({ active, payload, currency }: any) {
  if (!active || !payload?.length) return null;
  const p = payload[0];
  const text = `${new Date(p.payload.date).toLocaleDateString()}: ${formatMoney(p.value, currency)}`;
  return <div role="status" aria-live="polite" className="bg-popover text-popover-foreground p-2 rounded shadow text-sm">{text}</div>;
}

function EmptyChartState() {
  return (
    <div className="h-full flex flex-col items-center justify-center text-center p-6 border-dashed border-2 rounded">
      <ExampleChartIcon className="w-16 h-16 text-gray-300" />
      <h3 className="mt-3 font-medium">No revenue data yet</h3>
      <p className="text-sm text-gray-600 mt-1 max-w-sm">Once your first customer subscribes, you'll see daily ARR here. Try setting up a test plan to preview.</p>
      <a href="/billing/plans" className="mt-3 text-blue-600 underline text-sm">Configure plans</a>
    </div>
  );
}

function SinglePointChart({ point, currency }: { point: { date: Date; arr: number }; currency: string }) {
  return (
    <div className="h-full flex flex-col items-center justify-center text-center">
      <div className="text-3xl font-semibold">{formatMoney(point.arr, currency)}</div>
      <div className="text-sm text-gray-600 mt-1">First data point: {new Date(point.date).toLocaleDateString()}</div>
      <div className="text-xs text-gray-500 mt-3">A trend chart will appear after at least 2 data points.</div>
    </div>
  );
}

