// client/hooks/useOptimisticStar.ts
import { useCallback, useReducer, useRef } from 'react';
import { fetcher, FetchError } from '../lib/fetcher';
import { StarResponseSchema } from '@shared/schemas/star';
import { toast } from '../lib/toast';

type Override = { intent: boolean; requestId: number };

export function useStarOverrides() {
  const [, force] = useReducer((x: number) => x + 1, 0);
  const overrides = useRef<Map<string, Override>>(new Map());
  const requestCounter = useRef(0);
  const inflight = useRef<Map<string, AbortController>>(new Map());

  const isStarred = useCallback((id: string, serverStarred: boolean) => {
    return overrides.current.get(id)?.intent ?? serverStarred;
  }, []);

  const toggle = useCallback(async (id: string, currentServer: boolean) => {
    const next = !(overrides.current.get(id)?.intent ?? currentServer);
    const reqId = ++requestCounter.current;
    overrides.current.set(id, { intent: next, requestId: reqId });
    force();
    inflight.current.get(id)?.abort();
    const controller = new AbortController();
    inflight.current.set(id, controller);
    try {
      const result = await fetcher(`/api/projects/${id}/star`, {
        method: 'PUT',
        headers: { 'content-type': 'application/json' },
        body: JSON.stringify({ starred: next }),
        signal: controller.signal
      }, raw => StarResponseSchema.parse(raw));
      const current = overrides.current.get(id);
      if (current?.requestId === reqId) {
        overrides.current.delete(id);
        force();
      }
      return result;
    } catch (e) {
      if (controller.signal.aborted) return;
      const current = overrides.current.get(id);
      if (current?.requestId === reqId) {
        overrides.current.delete(id);
        force();
        const msg = e instanceof FetchError && e.body?.code === 'NOT_FOUND' ? 'Project no longer exists' : 'Could not save. Try again.';
        toast.error(msg, { action: { label: 'Retry', onClick: () => toggle(id, currentServer) } });
      }
    } finally { inflight.current.delete(id); }
  }, []);

  return { isStarred, toggle, isPending: (id: string) => overrides.current.has(id) };
}

// client/components/StarButton.tsx
import { useStarOverrides } from '../hooks/useOptimisticStar';
import { Star } from 'lucide-react';
export function StarButton({ projectId, serverStarred }: { projectId: string; serverStarred: boolean }) {
