// client/hooks/useDebounce.ts
import { useEffect, useRef, useState, useCallback } from 'react';
type Opts = { delay: number; leading?: boolean; trailing?: boolean; maxWait?: number };
export function useDebounce<T>(value: T, opts: Opts): [T, { flush: () => void; cancel: () => void }] {
  const { delay, leading = false, trailing = true, maxWait } = opts;
  const [debounced, setDebounced] = useState(value);
  const timerRef = useRef<number | null>(null);
  const maxTimerRef = useRef<number | null>(null);
  const lastValueRef = useRef(value);
  const lastInvokeRef = useRef(0);
  lastValueRef.current = value;
  const invoke = useCallback(() => {
    setDebounced(lastValueRef.current);
    lastInvokeRef.current = Date.now();
    if (maxTimerRef.current) { clearTimeout(maxTimerRef.current); maxTimerRef.current = null; }
  }, []);
  const cancel = useCallback(() => {
    if (timerRef.current) { clearTimeout(timerRef.current); timerRef.current = null; }
    if (maxTimerRef.current) { clearTimeout(maxTimerRef.current); maxTimerRef.current = null; }
  }, []);
  const flush = useCallback(() => { cancel(); invoke(); }, [cancel, invoke]);
  useEffect(() => {
    if (Object.is(value, debounced)) return;
    const now = Date.now();
    if (leading && !timerRef.current && (now - lastInvokeRef.current > delay)) invoke();
    if (timerRef.current) clearTimeout(timerRef.current);
    if (trailing) timerRef.current = window.setTimeout(() => { invoke(); timerRef.current = null; }, delay);
    if (maxWait && !maxTimerRef.current) maxTimerRef.current = window.setTimeout(invoke, maxWait);
    return () => {};
  }, [value, delay, leading, trailing, maxWait, invoke, debounced]);
  useEffect(() => cancel, [cancel]);
  return [debounced, { flush, cancel }];
}

// client/components/SearchInput.tsx
import { useState } from 'react';
import { useDebounce } from '../hooks/useDebounce';
export function SearchInput() {
  const [q, setQ] = useState('');
  const [debouncedQ, { flush }] = useDebounce(q, { delay: 300, trailing: true, maxWait: 1000 });
  return (
    <form onSubmit={e => { e.preventDefault(); flush(); }}>
      <input value={q} onChange={e => setQ(e.target.value)} aria-label="Search" />
      <SearchResults query={debouncedQ} />
    </form>
  );
}

