// client/hooks/useIntersection.ts
import { useCallback, useEffect, useRef, useState } from 'react';
type Key = string;
type Entry = { cb: (entry: IntersectionObserverEntry) => void };
const observers = new Map<Key, { observer: IntersectionObserver; targets: Map<Element, Entry> }>();
function keyOf(opts: IntersectionObserverInit) { return `${opts.root ?? 'window'}|${opts.rootMargin ?? ''}|${[opts.threshold ?? 0].flat().join(',')}`; }
function getOrCreate(opts: IntersectionObserverInit) {
  const k = keyOf(opts);
  let bucket = observers.get(k);
  if (!bucket) {
    const targets = new Map<Element, Entry>();
    const observer = new IntersectionObserver(entries => entries.forEach(e => targets.get(e.target)?.cb(e)), opts);
    bucket = { observer, targets };
    observers.set(k, bucket);
  }
  return bucket;
}
export function useIntersection<T extends Element = HTMLDivElement>(opts: IntersectionObserverInit & { once?: boolean } = {}) {
  const [entry, setEntry] = useState<IntersectionObserverEntry | null>(null);
  const elRef = useRef<T | null>(null);
  const setRef = useCallback((el: T | null) => {
    if (typeof IntersectionObserver === 'undefined') return;
    if (elRef.current) {
      const bucket = getOrCreate(opts);
      bucket.observer.unobserve(elRef.current);
      bucket.targets.delete(elRef.current);
    }
    elRef.current = el;
    if (el) {
      const bucket = getOrCreate(opts);
      bucket.targets.set(el, { cb: e => { setEntry(e); if (opts.once && e.isIntersecting) { bucket.observer.unobserve(el); bucket.targets.delete(el); } } });
      bucket.observer.observe(el);
    }
  }, [JSON.stringify(opts)]);
  useEffect(() => () => {
    if (elRef.current && typeof IntersectionObserver !== 'undefined') {
      const bucket = getOrCreate(opts);
      bucket.observer.unobserve(elRef.current);
      bucket.targets.delete(elRef.current);
    }
  }, []);
  return [setRef, entry?.isIntersecting ?? false, entry] as const;
}

