// server/middleware/idempotency.ts
import { RequestHandler } from 'express';
import { redis } from '../redis';
import { createHash } from 'crypto';
export const idempotency: RequestHandler = async (req, res, next) => {
  const key = req.header('idempotency-key');
  if (!key) return next();
  const fingerprint = createHash('sha256').update(`${req.user.id}:${req.method}:${req.path}:${JSON.stringify(req.body)}`).digest('hex');
  const cached = await redis.get(`idem:${key}`);
  if (cached) {
    const { fp, status, body } = JSON.parse(cached);
    if (fp !== fingerprint) return res.status(409).json({ code: 'IDEMPOTENCY_KEY_REUSED' });
    return res.status(status).json(body);
  }
  const origJson = res.json.bind(res);
  res.json = (body: any) => {
    redis.setex(`idem:${key}`, 86400, JSON.stringify({ fp: fingerprint, status: res.statusCode, body }));
    return origJson(body);
  };
  next();
};

