// client/lib/offlineQueue.ts
import { openDB, IDBPDatabase } from 'idb';
type QueuedReq = { id: string; url: string; method: string; headers: Record<string,string>; body: string; idempotencyKey: string; attempts: number; createdAt: number };
let dbp: Promise<IDBPDatabase> | null = null;
const getDb = () => dbp ??= openDB('mutation-queue', 1, { upgrade(d) { d.createObjectStore('queue', { keyPath: 'id' }); } });
export const offlineQueue = {
  async enqueue(req: Omit<QueuedReq, 'id'|'attempts'|'createdAt'>) {
    const db = await getDb();
    const id = crypto.randomUUID();
    await db.put('queue', { ...req, id, attempts: 0, createdAt: Date.now() });
    return id;
  },
  async size() { return (await getDb()).count('queue'); },
  async all(): Promise<QueuedReq[]> { return (await getDb()).getAll('queue'); },
  async remove(id: string) { return (await getDb()).delete('queue', id); },
  async incrementAttempts(id: string) {
    const db = await getDb();
    const item = await db.get('queue', id);
    if (item) { item.attempts++; await db.put('queue', item); }
  }
};

// client/lib/queueDrainer.ts
import { offlineQueue } from './offlineQueue';
const backoff = (a: number) => Math.min(60000, 1000 * 2 ** a) * (0.5 + Math.random() * 0.5);
let draining = false;
export async function drainQueue(onProgress?: (remaining: number) => void) {
  if (draining) return; draining = true;
  try {
    const items = await offlineQueue.all();
    for (const item of items.sort((a, b) => a.createdAt - b.createdAt)) {
      try {
        const res = await fetch(item.url, { method: item.method, headers: item.headers, body: item.body });
        if (res.ok || (res.status >= 400 && res.status < 500 && res.status !== 408 && res.status !== 429)) {
          await offlineQueue.remove(item.id);
        } else throw new Error(`${res.status}`);
      } catch {
        await offlineQueue.incrementAttempts(item.id);
        if (item.attempts >= 8) { await offlineQueue.remove(item.id); console.error('Dropping after 8 attempts', item); }
        else { await new Promise(r => setTimeout(r, backoff(item.attempts))); }
      }
      onProgress?.(await offlineQueue.size());
    }
  } finally { draining = false; }
}
if (typeof window !== 'undefined') window.addEventListener('online', () => drainQueue());

// client/components/QueueIndicator.tsx
import { useEffect, useState } from 'react';
import { offlineQueue } from '../lib/offlineQueue';
export function QueueIndicator() {
  const [size, setSize] = useState(0);
  useEffect(() => {
    const tick = async () => setSize(await offlineQueue.size());
    tick();
    const i = setInterval(tick, 2000);
    return () => clearInterval(i);
  }, []);
  if (size === 0) return null;
  return <div role="status" className="fixed bottom-4 right-4 bg-amber-100 border-amber-300 border px-3 py-2 rounded text-sm">{size} change{size > 1 ? 's' : ''} pending</div>;
}

