// server/services/onboardingService.ts
import { onboardingDal } from '../dal/onboardingDal';
import type { OnboardingState } from '@shared/schemas/onboarding';
import { workspaceService } from './workspaceService';
import { tenantContext } from '../context/tenantContext';
const STEP_ORDER = ['workspace','team','plan','integration','import','tour'] as const;
const REQUIRED = new Set(['workspace','plan']);
export const onboardingService = {
  async get(): Promise<OnboardingState> {
    const ctx = tenantContext.current()!;
    const rows = await onboardingDal.findByUser(ctx.userId);
    const steps = Object.fromEntries(STEP_ORDER.map(id => [id, rows.find(r => r.stepId === id) ?? { status: 'pending' as const }]));
    const currentStep = STEP_ORDER.find(s => steps[s].status === 'pending' && REQUIRED.has(s)) ?? STEP_ORDER.find(s => steps[s].status === 'pending') ?? 'tour';
    const allDone = STEP_ORDER.every(s => steps[s].status !== 'pending');
    return { currentStep, steps: steps as any, completedAt: allDone ? new Date() : undefined };
  },
  async submitStep(stepId: typeof STEP_ORDER[number], payload: any) {
    const ctx = tenantContext.current()!;
    const existing = await onboardingDal.findStep(ctx.userId, stepId);
    if (existing?.status === 'completed') return existing;
    switch (stepId) {
      case 'workspace': await workspaceService.create(payload); break;
      case 'team': for (const inv of payload.invites) await invitationService.send(inv); break;
    }
    return onboardingDal.markComplete(ctx.userId, stepId, payload);
  },
  async skipStep(stepId: typeof STEP_ORDER[number]) {
    if (REQUIRED.has(stepId)) throw new ForbiddenError('Cannot skip required step');
    const ctx = tenantContext.current()!;
    return onboardingDal.markSkipped(ctx.userId, stepId);
  }
};

