// client/hooks/useMetricStream.ts
import { useEffect, useRef, useState, useCallback } from 'react';
import { MetricTickSchema, type MetricTick } from '@shared/schemas/metric';
export function useMetricStream(url: string, maxPoints = 300) {
  const [points, setPoints] = useState<MetricTick[]>([]);
  const bufferRef = useRef<MetricTick[]>([]);
  const rafRef = useRef<number | null>(null);
  const pausedRef = useRef(false);
  const flush = useCallback(() => { setPoints(bufferRef.current.slice(-maxPoints)); rafRef.current = null; }, [maxPoints]);
  useEffect(() => {
    const onVis = () => { pausedRef.current = document.hidden; };
    document.addEventListener('visibilitychange', onVis);
    let es: EventSource | null = null;
    let retry = 0;
    const connect = () => {
      es = new EventSource(url);
      es.onmessage = (e) => {
        if (pausedRef.current) return;
        const parsed = MetricTickSchema.safeParse(JSON.parse(e.data));
        if (!parsed.success) return;
        bufferRef.current = [...bufferRef.current.slice(-(maxPoints - 1)), parsed.data];
        if (rafRef.current === null) rafRef.current = requestAnimationFrame(flush);
      };
      es.onerror = () => { es?.close(); setTimeout(connect, Math.min(30000, 1000 * 2 ** retry++)); };
    };
    connect();
    return () => { document.removeEventListener('visibilitychange', onVis); es?.close(); if (rafRef.current) cancelAnimationFrame(rafRef.current); };
  }, [url, maxPoints, flush]);
  return points;
}

