// client/components/OrgGraph.tsx
import { useEffect, useRef } from 'react';
import { forceSimulation, forceManyBody, forceLink, forceCollide, forceCenter } from 'd3-force';
import { Group } from '@visx/group';
import { Zoom } from '@visx/zoom';
import type { Graph } from '@shared/schemas/graph';
export function OrgGraph({ graph, width, height }: { graph: Graph; width: number; height: number }) {
  const nodes = useRef(graph.nodes.map(n => ({ ...n, x: width/2, y: height/2, vx: 0, vy: 0 })));
  const edges = useRef(graph.edges.map(e => ({ ...e })));
  const groupRef = useRef<SVGGElement>(null);
  const simRef = useRef<ReturnType<typeof forceSimulation> | null>(null);
  useEffect(() => {
    const sim = forceSimulation(nodes.current as any)
      .force('charge', forceManyBody().strength(-200))
      .force('link', forceLink(edges.current).id((d: any) => d.id).distance(60))
      .force('collide', forceCollide(30))
      .force('center', forceCenter(width/2, height/2))
      .on('tick', () => render());
    simRef.current = sim;
    function render() {
      const g = groupRef.current; if (!g) return;
      const gs = g.querySelectorAll<SVGGElement>('g.node');
      nodes.current.forEach((n: any, i) => { const el = gs[i]; if (el) el.setAttribute('transform', `translate(${n.x},${n.y})`); });
      const ls = g.querySelectorAll<SVGLineElement>('line.edge');
      edges.current.forEach((e: any, i) => { const el = ls[i]; if (el) { el.setAttribute('x1', e.source.x); el.setAttribute('y1', e.source.y); el.setAttribute('x2', e.target.x); el.setAttribute('y2', e.target.y); } });
    }
    return () => { sim.stop(); };
  }, [width, height]);
  const onPointerDown = (i: number) => (e: React.PointerEvent) => {
    (e.target as Element).setPointerCapture(e.pointerId);
    const move = (ev: PointerEvent) => { const n = nodes.current[i] as any; n.fx = ev.offsetX; n.fy = ev.offsetY; simRef.current?.alpha(0.3).restart(); };
    const up = (ev: PointerEvent) => { const n = nodes.current[i] as any; n.fx = null; n.fy = null; (e.target as Element).releasePointerCapture(ev.pointerId); window.removeEventListener('pointermove', move); window.removeEventListener('pointerup', up); };
    window.addEventListener('pointermove', move); window.addEventListener('pointerup', up);
  };
  return (
    <Zoom width={width} height={height} scaleXMin={0.25} scaleXMax={4} scaleYMin={0.25} scaleYMax={4}>
      {zoom => (
        <svg width={width} height={height} ref={zoom.containerRef as any}>
          <g transform={zoom.toString()} ref={groupRef}>
            {edges.current.map((e, i) => <line key={i} className="edge" stroke="var(--chart-axis)" strokeWidth={1} />)}
            {nodes.current.map((n, i) => (
              <g key={n.id} className="node" onPointerDown={onPointerDown(i)}>
                <circle r={20} fill="var(--chart-node)" />
                <text textAnchor="middle" dy={4} fontSize={10}>{n.label.slice(0, 8)}</text>
              </g>
            ))}
          </g>
        </svg>
      )}
    </Zoom>
  );
}

