import { LineChart, Line, XAxis, YAxis, Tooltip, Legend, ResponsiveContainer } from 'recharts';
import { OKABE_ITO, SERIES_STYLES } from '../lib/palette';
import type { z } from 'zod';
import type { MultiSeriesSchema } from '@shared/schemas/multiSeries';
export function AccessibleSeriesChart({ series }: { series: z.infer<typeof MultiSeriesSchema> }) {
  const summary = series.map(s => `${s.label}: ${s.points.length} points, last ${s.points.at(-1)?.y ?? 'N/A'}`).join('. ');
  const merged = mergeByX(series);
  return (
    <figure>
      <figcaption className="sr-only">{summary}</figcaption>
      <div role="img" aria-label={summary} className="h-80">
        <ResponsiveContainer width="100%" height="100%">
          <LineChart data={merged}>
            <XAxis dataKey="x" stroke="var(--chart-axis)" />
            <YAxis stroke="var(--chart-axis)" />
            <Tooltip />
            <Legend />
            {series.map((s, i) => (
              <Line key={s.id} type="monotone" dataKey={s.id} name={s.label} stroke={OKABE_ITO[i % OKABE_ITO.length]} strokeDasharray={SERIES_STYLES[i % SERIES_STYLES.length].dash} dot={{ r: 3 }} activeDot={{ r: 6 }} />
            ))}
          </LineChart>
        </ResponsiveContainer>
      </div>
      <details className="mt-2 text-sm">
        <summary>View data as table</summary>
        <table className="mt-2 w-full text-left">
          <thead><tr><th>Date</th>{series.map(s => <th key={s.id}>{s.label}</th>)}</tr></thead>
          <tbody>{merged.map(row => <tr key={String(row.x)}><td>{new Date(row.x).toLocaleDateString()}</td>{series.map(s => <td key={s.id}>{row[s.id] ?? '—'}</td>)}</tr>)}</tbody>
        </table>
      </details>
    </figure>
  );
}
function mergeByX(series: z.infer<typeof MultiSeriesSchema>) {
  const map = new Map<number, any>();
  for (const s of series) for (const p of s.points) {
    const k = +new Date(p.x);
    const row = map.get(k) ?? { x: k };
    row[s.id] = p.y;
    map.set(k, row);
  }
  return [...map.values()].sort((a, b) => a.x - b.x);
}

