// client/components/DocEditor.tsx
import { useState } from 'react';
import { DocSchema, type Doc } from '@shared/schemas/doc';
import { fetcher, FetchError } from '../lib/fetcher';
import { ConflictResolver } from './ConflictResolver';
export function DocEditor({ initial }: { initial: Doc }) {
  const [doc, setDoc] = useState(initial);
  const [draft, setDraft] = useState({ title: initial.title, body: initial.body });
  const [conflict, setConflict] = useState<{ theirs: Doc; mine: typeof draft } | null>(null);
  const save = async () => {
    try {
      const saved = await fetcher<Doc>(`/api/docs/${doc.id}`, { method: 'PUT', headers: { 'content-type': 'application/json' }, body: JSON.stringify({ ...draft, expectedVersion: doc.version }) }, raw => DocSchema.parse(raw));
      setDoc(saved); setDraft({ title: saved.title, body: saved.body });
    } catch (e) {
      if (e instanceof FetchError && e.body?.code === 'CONFLICT') {
        const theirs = DocSchema.parse((e.body.meta as any).current);
        setConflict({ theirs, mine: draft });
      } else throw e;
    }
  };
  if (conflict) return <ConflictResolver theirs={conflict.theirs} mine={conflict.mine} onResolve={resolved => { setDoc(conflict.theirs); setDraft(resolved); setConflict(null); }} />;
  return (
    <div>
      <input value={draft.title} onChange={e => setDraft(d => ({ ...d, title: e.target.value }))} />
      <textarea value={draft.body} onChange={e => setDraft(d => ({ ...d, body: e.target.value }))} />
      <button onClick={save}>Save (v{doc.version})</button>
    </div>
  );
}

// client/components/ConflictResolver.tsx
import { useState } from 'react';
import type { Doc } from '@shared/schemas/doc';
export function ConflictResolver({ theirs, mine, onResolve }: { theirs: Doc; mine: { title: string; body: string }; onResolve: (r: { title: string; body: string }) => void }) {
  const [resolved, setResolved] = useState(mine);
  return (
    <div role="dialog" aria-label="Conflict resolution">
      <p>Another user saved changes. Pick how to merge.</p>
      <Section field="title" theirs={theirs.title} mine={mine.title} value={resolved.title} onChange={v => setResolved(r => ({ ...r, title: v }))} />
      <Section field="body" theirs={theirs.body} mine={mine.body} value={resolved.body} onChange={v => setResolved(r => ({ ...r, body: v }))} />
      <button onClick={() => onResolve(resolved)}>Save merged</button>
      <button onClick={() => onResolve({ title: theirs.title, body: theirs.body })}>Discard mine</button>
    </div>
  );
}

