// server/services/impersonationService.ts
import { ImpersonationSessionModel, AuditLogModel } from '../models';
import { signJwt } from '../auth/jwt';
import { ForbiddenError } from '../errors';
const MAX_DURATION_MS = 30 * 60 * 1000;
const BLOCKED_ACTIONS = new Set(['account:delete','email:change','password:reset','billing:source_update','2fa:disable']);
export const impersonationService = {
  async start(adminId: string, input: { targetUserId: string; reason: string; ticketRef: string }) {
    const admin = await userDal.byId(adminId);
    if (admin.role !== 'support_admin' && admin.role !== 'super_admin') throw new ForbiddenError('Not allowed to impersonate');
    const session = await ImpersonationSessionModel.create({
      adminId,
      targetUserId: input.targetUserId,
      reason: input.reason,
      ticketRef: input.ticketRef,
      startedAt: new Date(),
      expiresAt: new Date(Date.now() + MAX_DURATION_MS),
      revokedAt: null
    });
    await AuditLogModel.create({ actorId: adminId, subjectId: input.targetUserId, action: 'impersonation:start', metadata: { reason: input.reason, ticketRef: input.ticketRef, sessionId: session._id } });
    return signJwt({ userId: input.targetUserId, actorId: adminId, impersonationSessionId: session._id.toString(), exp: Math.floor(session.expiresAt.getTime() / 1000) });
  },
  async end(sessionId: string, adminId: string) {
    await ImpersonationSessionModel.updateOne({ _id: sessionId, adminId }, { revokedAt: new Date() });
    await AuditLogModel.create({ actorId: adminId, action: 'impersonation:end', metadata: { sessionId } });
  },
  guardAction(action: string) {
    if (BLOCKED_ACTIONS.has(action)) throw new ForbiddenError('Action blocked during impersonation');
  }
};

// server/middleware/impersonationContext.ts
import { RequestHandler } from 'express';
export const impersonationContext: RequestHandler = (req, _res, next) => {
  const token = (req as any).jwt;
  if (token?.actorId) {
    (req as any).user = { ...token, id: token.userId };
    (req as any).actor = { id: token.actorId, impersonationSessionId: token.impersonationSessionId };
  }
  next();
};

// server/middleware/auditLog.ts — wraps every mutation
import { RequestHandler } from 'express';
import { AuditLogModel } from '../models';
export const auditLog = (action: string): RequestHandler => async (req, res, next) => {
  const actor = (req as any).actor;
  if (actor) impersonationService.guardAction(action);
  res.on('finish', () => {
    if (res.statusCode < 400) AuditLogModel.create({
      actorId: actor?.id ?? (req as any).user.id,
      subjectId: (req as any).user.id,
      isImpersonation: !!actor,
      sessionId: actor?.impersonationSessionId,
      action,
      path: req.path,
      method: req.method
    });
  });
  next();
};

