// client/lib/stats.ts
export function quartiles(values: number[]) {
  const sorted = [...values].sort((a, b) => a - b);
  const q = (p: number) => sorted[Math.floor((sorted.length - 1) * p)];
  const q1 = q(0.25), q3 = q(0.75);
  const iqr = q3 - q1;
  return { q1, q3, iqr, lowerFence: q1 - 1.5 * iqr, upperFence: q3 + 1.5 * iqr };
}

// client/components/LatencyChart.tsx
import { useMemo, useState } from 'react';
import { LineChart, Line, XAxis, YAxis, Tooltip, ResponsiveContainer, ReferenceDot } from 'recharts';
import { quartiles } from '../lib/stats';
import type { z } from 'zod';
import type { TimeSeriesSchema } from '@shared/schemas/timeseries';
export function LatencyChart({ series }: { series: z.infer<typeof TimeSeriesSchema> }) {
  const [mode, setMode] = useState<'crop' | 'all' | 'log'>('crop');
  const { fences, outliers, capped } = useMemo(() => {
    const vals = series.points.map(p => p.value);
    const f = quartiles(vals);
    const outs = series.points.filter(p => p.value > f.upperFence);
    const cappedY = f.upperFence * 1.1;
    const c = series.points.map(p => p.value > f.upperFence ? { ...p, displayValue: cappedY, isOutlier: true } : { ...p, displayValue: p.value, isOutlier: false });
    return { fences: f, outliers: outs, capped: c };
  }, [series]);
  const data = mode === 'crop' ? capped : series.points.map(p => ({ ...p, displayValue: p.value }));
  return (
    <div>
      <div className="flex justify-between items-center text-sm mb-2">
        <span>{outliers.length} outliers (> {fences.upperFence.toFixed(0)}{series.unit})</span>
        <div className="flex gap-1">
          <button onClick={() => setMode('crop')} aria-pressed={mode === 'crop'}>Crop</button>
          <button onClick={() => setMode('all')} aria-pressed={mode === 'all'}>All</button>
          <button onClick={() => setMode('log')} aria-pressed={mode === 'log'}>Log</button>
        </div>
      </div>
      <div className="h-64">
        <ResponsiveContainer width="100%" height="100%">
          <LineChart data={data}>
            <XAxis dataKey="t" tickFormatter={t => new Date(t).toLocaleTimeString()} />
            <YAxis scale={mode === 'log' ? 'log' : 'auto'} domain={mode === 'log' ? [1, 'auto'] : ['auto', 'auto']} tickFormatter={v => `${v}${series.unit}`} />
            <Tooltip formatter={(v: any, _name, item) => [`${(item.payload as any).value}${series.unit}${(item.payload as any).isOutlier ? ' (outlier)' : ''}`, 'Latency']} />
            <Line dataKey="displayValue" stroke="var(--chart-line)" dot={false} />
          </LineChart>
        </ResponsiveContainer>
      </div>
    </div>
  );
}

