// server/services/usageService.ts
import { UsageEventModel } from '../models/UsageEvent';
import { tenantContext } from '../context/tenantContext';
export const usageService = {
  async ingestBatch(events: any[]) {
    const tenantId = tenantContext.requireTenant();
    const docs = events.map(e => ({ ...e, tenantId }));
    try {
      const r = await UsageEventModel.insertMany(docs, { ordered: false });
      return { accepted: r.length, deduped: 0 };
    } catch (err: any) {
      const inserted = err.insertedDocs?.length ?? 0;
      const writeErrors = err.writeErrors ?? [];
      return { accepted: inserted, deduped: writeErrors.filter((w: any) => w.code === 11000).length };
    }
  },
  async previewCurrentPeriod() {
    const tenantId = tenantContext.requireTenant();
    const periodStart = startOfMonth();
    const events = await UsageEventModel.aggregate([
      { $match: { tenantId, occurredAt: { $gte: periodStart } } },
      { $group: { _id: '$kind', total: { $sum: '$quantity' } } }
    ]);
    const lineItems = events.map(e => ({ kind: e._id, quantity: e.total, unitPrice: PRICE_PER_UNIT[e._id], total: e.total * PRICE_PER_UNIT[e._id] }));
    return { periodStart, periodEnd: endOfMonth(), lineItems, total: lineItems.reduce((s, l) => s + l.total, 0) };
  }
};

// server/jobs/syncStripeUsage.ts — hourly
import Stripe from 'stripe';
import { UsageEventModel, StripeSyncCursorModel } from '../models';
const stripe = new Stripe(process.env.STRIPE_SECRET_KEY!);
export async function syncStripeUsage() {
  const tenants = await tenantDal.allWithMetering();
  for (const tenant of tenants) {
    const cursor = await StripeSyncCursorModel.findOne({ tenantId: tenant.id }) ?? { syncedThrough: tenant.createdAt };
    const now = new Date();
    const events = await UsageEventModel.aggregate([
      { $match: { tenantId: tenant.id, occurredAt: { $gt: cursor.syncedThrough, $lte: now } } },
      { $group: { _id: '$kind', total: { $sum: '$quantity' } } }
    ]);
    for (const e of events) {
      const subItem = tenant.stripeSubscriptionItemIdByKind[e._id];
      await stripe.subscriptionItems.createUsageRecord(subItem, { quantity: Math.ceil(e.total), action: 'increment', timestamp: Math.floor(now.getTime() / 1000) });
    }
    await StripeSyncCursorModel.updateOne({ tenantId: tenant.id }, { syncedThrough: now }, { upsert: true });
  }
}

