// client/lib/usageReporter.ts
import { fetcher } from './fetcher';
import { UsageEventSchema } from '@shared/schemas/usage';
import type { z } from 'zod';
type Event = z.input<typeof UsageEventSchema>;
class UsageReporter {
  private queue: Event[] = [];
  private timer: number | null = null;
  track(kind: Event['kind'], quantity: number, metadata?: Record<string, string>) {
    this.queue.push({ idempotencyKey: crypto.randomUUID(), kind, quantity, occurredAt: new Date(), metadata });
    if (this.queue.length >= 100) this.flush();
    else this.timer ??= window.setTimeout(() => this.flush(), 30000);
  }
  async flush() {
    if (this.timer) { clearTimeout(this.timer); this.timer = null; }
    if (!this.queue.length) return;
    const batch = this.queue.splice(0);
    try { await fetcher('/api/usage/events', { method: 'POST', headers: { 'content-type': 'application/json' }, body: JSON.stringify({ events: batch }) }, () => undefined); }
    catch { this.queue.unshift(...batch); }
  }
}
export const usage = new UsageReporter();
if (typeof window !== 'undefined') window.addEventListener('beforeunload', () => usage.flush());

