import { logger } from '../logger';
import type { User } from '../models/User';
const DEPRECATED_FIELDS = ['legacy_user_name'];
export function serializeUser(user: User, opts: { telemetryTag?: string } = {}) {
  const base = {
    id: user.id,
    fullName: user.fullName,
    legacy_user_name: user.fullName
  };
  return new Proxy(base, {
    get(target, prop) {
      if (DEPRECATED_FIELDS.includes(prop as string)) {
        logger.warn({ field: prop, telemetryTag: opts.telemetryTag }, 'deprecated_field_accessed_server');
      }
      return target[prop as keyof typeof target];
    }
  });
}

