// client/lib/deprecationProxy.ts — wrap fetch results to track deprecated field reads
import { analytics } from './analytics';
export function withDeprecation<T extends object>(obj: T, deprecated: (keyof T)[], context: string): T {
  return new Proxy(obj, {
    get(target, prop) {
      if (deprecated.includes(prop as keyof T)) {
        analytics.track('deprecated_field_read', { field: prop as string, context });
        if (process.env.NODE_ENV === 'development') console.warn(`Deprecated field read: ${String(prop)} at ${context}`);
      }
      return target[prop as keyof T];
    }
  });
}

