// server/routes/auth.ts
import { Router } from 'express';
import { authService } from '../services/authService';
import { UnauthorizedError } from '../errors';
export const authRouter = Router();
authRouter.post('/auth/refresh', async (req, res, next) => {
  const refreshToken = req.cookies['refresh_token'];
  if (!refreshToken) return next(new UnauthorizedError('No refresh token'));
  try {
    const { accessToken, expiresAt, newRefreshToken } = await authService.refresh(refreshToken);
    res.cookie('refresh_token', newRefreshToken, { httpOnly: true, secure: true, sameSite: 'strict', maxAge: 30 * 86400 * 1000 });
    res.json({ accessToken, expiresAt });
  } catch { next(new UnauthorizedError('Invalid refresh token')); }
});
authRouter.post('/auth/logout', async (req, res) => {
  const refreshToken = req.cookies['refresh_token'];
  if (refreshToken) await authService.revoke(refreshToken);
  res.clearCookie('refresh_token');
  res.status(204).end();
});

// server/middleware/auth.ts
import { RequestHandler } from 'express';
import { UnauthorizedError } from '../errors';
import jwt from 'jsonwebtoken';
export const authMiddleware: RequestHandler = (req, _res, next) => {
  const header = req.header('authorization');
  if (!header?.startsWith('Bearer ')) return next(new UnauthorizedError('No token'));
  try {
    const decoded = jwt.verify(header.slice(7), process.env.JWT_SECRET!);
    (req as any).user = decoded;
    next();
  } catch (err: any) {
    if (err.name === 'TokenExpiredError') return next(new UnauthorizedError('Token expired', { meta: { code: 'TOKEN_EXPIRED' } }));
    next(new UnauthorizedError('Invalid token'));
  }
};

