// client/lib/authClient.ts
import { RefreshResponseSchema } from '@shared/schemas/auth';
let accessToken: string | null = null;
let refreshPromise: Promise<string> | null = null;
export const auth = {
  setAccessToken(t: string) { accessToken = t; },
  getAccessToken() { return accessToken; },
  async refresh(): Promise<string> {
    if (refreshPromise) return refreshPromise;
    refreshPromise = (async () => {
      try {
        const res = await fetch('/api/auth/refresh', { method: 'POST', credentials: 'include' });
        if (!res.ok) throw new Error('Refresh failed');
        const parsed = RefreshResponseSchema.parse(await res.json());
        accessToken = parsed.accessToken;
        return accessToken;
      } finally { refreshPromise = null; }
    })();
    return refreshPromise;
  },
  async logout() {
    accessToken = null;
    await fetch('/api/auth/logout', { method: 'POST', credentials: 'include' });
  }
};

// client/lib/authedFetch.ts
import { auth } from './authClient';
export async function authedFetch(input: RequestInfo, init: RequestInit = {}): Promise<Response> {
  const doFetch = async (token: string | null) => {
    const headers = new Headers(init.headers);
    if (token) headers.set('authorization', `Bearer ${token}`);
    return fetch(input, { ...init, headers, credentials: 'include' });
  };
  let res = await doFetch(auth.getAccessToken());
  if (res.status === 401) {
    const body = await res.clone().json().catch(() => null);
    if (body?.meta?.code === 'TOKEN_EXPIRED' || body?.code === 'UNAUTHORIZED') {
      try {
        const newToken = await auth.refresh();
        res = await doFetch(newToken);
      } catch {
        window.location.assign('/login?reason=session_expired&returnTo=' + encodeURIComponent(window.location.pathname));
      }
    }
  }
  return res;
}

// client/hooks/useSessionExpiryWarning.ts — proactive warning
import { useEffect } from 'react';
import { auth } from '../lib/authClient';
import { toast } from '../lib/toast';
export function useSessionExpiryWarning(expiresAt: Date) {
  useEffect(() => {
    const warnAt = expiresAt.getTime() - 60_000;
    const now = Date.now();
    if (warnAt <= now) return;
    const t = setTimeout(() => {
      toast.warning('Session expiring soon', { action: { label: 'Stay signed in', onClick: () => auth.refresh() } });
    }, warnAt - now);
    return () => clearTimeout(t);
  }, [expiresAt]);
}
